    "datePublished":isoDate(pub),"dateModified":isoDate(mod),
    "author":{"@type":"Organization","name":BRAND},"publisher":{"@type":"Organization","name":BRAND},
    "mainEntityOfPage":url,"image":photoFor(seed),"about":R.n+" 포스기·카드단말기 설치",
