// ---------- 검색 ----------
function findRegions(qstr,limit){
  const q=qstr.trim(); if(!q) return [];
  const out=[];
  for(const r of REGIONS){ if(r.n.indexOf(q)>=0){ out.push(r); if(out.length>=limit) break; } }
  return out;
}
