function resp(html,type,extra){
  return new Response(html,{headers:Object.assign({"content-type":type,"cache-control":"public, max-age=600"},extra||{})});
}

export default {
  async fetch(request){
    const url=new URL(request.url);
    let path=decodeURIComponent(url.pathname);
    if(path==="/") return resp(homePage(),"text/html; charset=UTF-8");
    if(path==="/robots.txt") return new Response(ROBOTS,{headers:{"content-type":"text/plain; charset=UTF-8","cache-control":"no-cache, no-store, max-age=0"}});
    if(path==="/llms.txt") return resp(LLMS_TXT,"text/plain; charset=UTF-8");
    if(GOOGLE_VERIFY_FILE && path==="/"+GOOGLE_VERIFY_FILE) return resp("google-site-verification: "+GOOGLE_VERIFY_FILE,"text/plain; charset=UTF-8");
    if(BING_VERIFY && path==="/BingSiteAuth.xml") return resp('<?xml version="1.0"?><users><user>'+BING_VERIFY+'</user></users>',"application/xml; charset=UTF-8");
    if(INDEXNOW_KEY && path==="/"+INDEXNOW_KEY+".txt") return resp(INDEXNOW_KEY,"text/plain; charset=UTF-8");
    if(path==="/indexnow/today"||path==="/indexnow/all"){
      if(url.searchParams.get("key")!==INDEXNOW_KEY) return new Response("forbidden",{status:403});
      const urls=path.endsWith("/all")?allUrls():todaysUpdatedUrls();
      const res=await submitIndexNow(urls);
      return new Response(JSON.stringify({requested:urls.length,sent:res.sent,batches:res.batches}),{headers:{"content-type":"application/json; charset=UTF-8"}});
    }
    if(path==="/sitemap.xml") return resp(sitemap(),"application/xml; charset=UTF-8");
    if(path==="/rss.xml"||path==="/feed.xml"||path==="/rss"||path==="/feed") return resp(rssFeed(),"application/rss+xml; charset=UTF-8");
    if(path==="/atom.xml"||path==="/atom") return resp(atomFeed(),"application/atom+xml; charset=UTF-8");
    if(path==="/list"||path==="/sitemap.html") return resp(listPage(),"text/html; charset=UTF-8");
    if(path==="/og.svg") return resp(OG_SVG,"image/svg+xml");
    if(path==="/favicon.svg") return resp(FAVICON_SVG,"image/svg+xml");
    if(path==="/favicon.ico") return new Response(b64bytes(FAVICON_ICO_B64),{headers:{"content-type":"image/x-icon","cache-control":"public, max-age=86400"}});
    if(path==="/favicon-48.png") return new Response(b64bytes(FAVICON_PNG48_B64),{headers:{"content-type":"image/png","cache-control":"public, max-age=86400"}});
    if(path==="/apple-touch-icon.png"||path==="/apple-touch-icon-precomposed.png") return new Response(b64bytes(APPLE_PNG_B64),{headers:{"content-type":"image/png","cache-control":"public, max-age=86400"}});
    if(path==="/api/find"){
      const q=url.searchParams.get("q")||"";
      const data=findRegions(q,30).map(r=>({n:r.n,s:r.s}));
      return new Response(JSON.stringify(data),{headers:{"content-type":"application/json; charset=UTF-8","cache-control":"public, max-age=300"}});
    }
    if(path==="/find") return resp(findPage(url.searchParams.get("q")||""),"text/html; charset=UTF-8");
    if(path.startsWith("/sido/")){
      const s=SLUG2SIDO.get(path.slice(6));
      if(s) return resp(sidoPage(s),"text/html; charset=UTF-8");
    }
    if(path.startsWith("/sigungu/")){
      const info=SLUG2GUNGU.get(path.slice(9));
      if(info) return resp(sigunguPage(info),"text/html; charset=UTF-8");
    }
    if(path.startsWith("/r/")){
      const slug=path.slice(3);
      const R=BY_SLUG.get(slug);
      if(R) return resp(regionPage(R),"text/html; charset=UTF-8");
    }
    return new Response(notFound(),{status:404,headers:{"content-type":"text/html; charset=UTF-8"}});
  },
  async scheduled(event,env,ctx){
    ctx.waitUntil(submitIndexNow(todaysUpdatedUrls()));
  }
};